import React, { useState } from 'react';
import { useNFT } from '../contexts/NFTContext';
import { useWallet } from '../contexts/WalletContext';
import {
  ShoppingCart,
  Eye,
  Filter,
  Search,
  Coins,
  Users,
  Calendar,
  CheckCircle,
  Loader,
  ExternalLink
} from 'lucide-react';

const Marketplace = () => {
  const { marketplaceListings, purchaseNFT } = useNFT();
  const { walletAddress } = useWallet();
  const [searchTerm, setSearchTerm] = useState('');
  const [sortBy, setSortBy] = useState('newest');
  const [priceFilter, setPriceFilter] = useState('all');
  const [selectedNFT, setSelectedNFT] = useState(null);
  const [purchasing, setPurchasing] = useState(null);

  const formatAddress = (address) => {
    return `${address.slice(0, 6)}...${address.slice(-4)}`;
  };

  const filteredListings = marketplaceListings
    .filter(listing =>
      listing.nftName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      listing.roomName.toLowerCase().includes(searchTerm.toLowerCase())
    )
    .filter(listing => {
      if (priceFilter === 'all') return true;
      const price = parseFloat(listing.price);
      switch (priceFilter) {
        case 'under-0.1': return price < 0.1;
        case '0.1-0.5': return price >= 0.1 && price <= 0.5;
        case 'over-0.5': return price > 0.5;
        default: return true;
      }
    })
    .sort((a, b) => {
      switch (sortBy) {
        case 'price-low': return parseFloat(a.price) - parseFloat(b.price);
        case 'price-high': return parseFloat(b.price) - parseFloat(a.price);
        case 'popular': return b.sold - a.sold;
        case 'newest': return new Date(b.createdAt) - new Date(a.createdAt);
        default: return 0;
      }
    });

  const handlePurchase = async (listingId) => {
    setPurchasing(listingId);
    try {
      const result = await purchaseNFT(listingId, walletAddress);
      if (result.success) {
        alert(`Successfully purchased NFT! Token ID: ${result.tokenId}`);
        setSelectedNFT(null);
      }
    } catch (error) {
      alert('Failed to purchase NFT: ' + error.message);
    } finally {
      setPurchasing(null);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">NFT Marketplace</h1>
          <p className="text-gray-600">Discover and purchase room access NFTs</p>
        </div>
      </div>

      {/* Search and Filters */}
      <div className="card">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="relative">
            <Search className="w-4 h-4 absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
            <input
              type="text"
              placeholder="Search NFTs or rooms..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="input-field pl-10"
            />
          </div>

          <select
            value={sortBy}
            onChange={(e) => setSortBy(e.target.value)}
            className="input-field"
          >
            <option value="newest">Newest First</option>
            <option value="price-low">Price: Low to High</option>
            <option value="price-high">Price: High to Low</option>
            <option value="popular">Most Popular</option>
          </select>

          <select
            value={priceFilter}
            onChange={(e) => setPriceFilter(e.target.value)}
            className="input-field"
          >
            <option value="all">All Prices</option>
            <option value="under-0.1">Under 0.1 ETH</option>
            <option value="0.1-0.5">0.1 - 0.5 ETH</option>
            <option value="over-0.5">Over 0.5 ETH</option>
          </select>

          <div className="flex items-center space-x-2 text-sm text-gray-600">
            <Filter className="w-4 h-4" />
            <span>{filteredListings.length} NFTs found</span>
          </div>
        </div>
      </div>

      {/* NFT Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredListings.map((listing) => (
          <div key={listing.id} className="card hover:shadow-lg transition-shadow duration-200">
            <div className="relative">
              <img
                src={listing.image}
                alt={listing.nftName}
                className="w-full h-48 object-cover rounded-lg mb-4"
              />
              <div className="absolute top-2 right-2 bg-black bg-opacity-70 text-white px-2 py-1 rounded text-xs">
                {listing.sold}/{listing.totalSupply} sold
              </div>
            </div>

            <div className="space-y-3">
              <div>
                <h3 className="font-semibold text-gray-900">{listing.nftName}</h3>
                <p className="text-sm text-gray-600">{listing.roomName}</p>
              </div>

              <p className="text-sm text-gray-700 line-clamp-2">{listing.description}</p>

              <div className="flex items-center justify-between text-sm text-gray-500">
                <div className="flex items-center space-x-1">
                  <Users className="w-4 h-4" />
                  <span>{listing.sold} owners</span>
                </div>
                <div className="flex items-center space-x-1">
                  <Calendar className="w-4 h-4" />
                  <span>{listing.createdAt.toLocaleDateString()}</span>
                </div>
              </div>

              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-2">
                  <Coins className="w-5 h-5 text-gray-600" />
                  <span className="text-lg font-bold text-gray-900">
                    {listing.price} {listing.currency}
                  </span>
                </div>
                <div className="text-xs text-gray-500">
                  by {formatAddress(listing.seller)}
                </div>
              </div>

              <div className="flex space-x-2">
                <button
                  onClick={() => setSelectedNFT(listing)}
                  className="flex-1 btn-secondary flex items-center justify-center space-x-2"
                >
                  <Eye className="w-4 h-4" />
                  <span>View Details</span>
                </button>
                <button
                  onClick={() => handlePurchase(listing.id)}
                  disabled={purchasing === listing.id || listing.sold >= listing.totalSupply}
                  className="flex-1 btn-primary flex items-center justify-center space-x-2 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {purchasing === listing.id ? (
                    <Loader className="w-4 h-4 animate-spin" />
                  ) : (
                    <ShoppingCart className="w-4 h-4" />
                  )}
                  <span>
                    {purchasing === listing.id ? 'Buying...' :
                      listing.sold >= listing.totalSupply ? 'Sold Out' : 'Buy Now'}
                  </span>
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {filteredListings.length === 0 && (
        <div className="text-center py-12">
          <ShoppingCart className="w-16 h-16 text-gray-300 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-gray-900 mb-2">No NFTs found</h3>
          <p className="text-gray-600">Try adjusting your search or filters</p>
        </div>
      )}

      {/* NFT Detail Modal */}
      {selectedNFT && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg max-w-2xl w-full max-h-[90vh] overflow-y-auto">
            <div className="p-6">
              <div className="flex items-center justify-between mb-6">
                <h2 className="text-xl font-bold text-gray-900">NFT Details</h2>
                <button
                  onClick={() => setSelectedNFT(null)}
                  className="p-2 hover:bg-gray-100 rounded-lg"
                >
                  ×
                </button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <img
                    src={selectedNFT.image}
                    alt={selectedNFT.nftName}
                    className="w-full rounded-lg"
                  />
                </div>

                <div className="space-y-4">
                  <div>
                    <h3 className="text-lg font-semibold text-gray-900">{selectedNFT.nftName}</h3>
                    <p className="text-gray-600">{selectedNFT.roomName}</p>
                  </div>

                  <p className="text-gray-700">{selectedNFT.description}</p>

                  <div className="space-y-3">
                    <div className="flex justify-between">
                      <span className="text-gray-600">Price:</span>
                      <div className="flex items-center space-x-1">
                        <Coins className="w-4 h-4" />
                        <span className="font-semibold">{selectedNFT.price} {selectedNFT.currency}</span>
                      </div>
                    </div>

                    <div className="flex justify-between">
                      <span className="text-gray-600">Supply:</span>
                      <span>{selectedNFT.sold}/{selectedNFT.totalSupply}</span>
                    </div>

                    <div className="flex justify-between">
                      <span className="text-gray-600">Seller:</span>
                      <span className="font-mono text-sm">{formatAddress(selectedNFT.seller)}</span>
                    </div>

                    <div className="flex justify-between">
                      <span className="text-gray-600">Created:</span>
                      <span>{selectedNFT.createdAt.toLocaleDateString()}</span>
                    </div>
                  </div>

                  <div className="pt-4 border-t">
                    <div className="flex space-x-3">
                      <button
                        onClick={() => handlePurchase(selectedNFT.id)}
                        disabled={purchasing === selectedNFT.id || selectedNFT.sold >= selectedNFT.totalSupply}
                        className="flex-1 btn-primary flex items-center justify-center space-x-2 disabled:opacity-50 disabled:cursor-not-allowed"
                      >
                        {purchasing === selectedNFT.id ? (
                          <Loader className="w-4 h-4 animate-spin" />
                        ) : (
                          <ShoppingCart className="w-4 h-4" />
                        )}
                        <span>
                          {purchasing === selectedNFT.id ? 'Purchasing...' :
                            selectedNFT.sold >= selectedNFT.totalSupply ? 'Sold Out' : 'Purchase NFT'}
                        </span>
                      </button>
                      <button className="btn-secondary flex items-center space-x-2">
                        <ExternalLink className="w-4 h-4" />
                        <span>View on Etherscan</span>
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Marketplace;
